function _setFeeRate(uint256 _newFeeRate) internal {
    if (_newFeeRate > TOTAL_BASIS_POINTS) revert FeeValueExceed100Percent();

    uint256 oldFeeRate = feeRate;
    uint256 newFeeRate = _newFeeRate;

    feeRate = uint16(newFeeRate);

    emit FeeRateSet(msg.sender, oldFeeRate, newFeeRate);
}

function setTokenURIExtension(uint256[] calldata tokenIds, string[] calldata uris) external override {
    requireExtension();
    require(tokenIds.length == uris.length, "Invalid input");
    for (uint256 i; i < tokenIds.length;) {
        _setTokenURIExtension(tokenIds[i], uris[i]);
        unchecked {
            ++i;
        }
    }
}

function _deposit(address caller, address receiver, uint256 assets, uint256 shares) internal virtual override {
    uint256 fee = _feeOnTotal(assets, _entryFeeBasisPoints());
    address recipient = _entryFeeRecipient();

    super._deposit(caller, receiver, assets, shares);

    if (fee > 0 && recipient != address(this)) {
        SafeERC20.safeTransfer(IERC20(asset()), recipient, fee);
    }
}

function release(address token) public virtual {
    VestingWalletStorage storage $ = _getVestingWalletStorage();
    uint256 amount = releasable(token);
    $._erc20Released[token] += amount;
    emit ERC20Released(token, amount);
    SafeERC20.safeTransfer(IERC20(token), owner(), amount);
}

function __ERC20Wrapper_init_unchained(IERC20 underlyingToken) internal onlyInitializing {
    ERC20WrapperStorage storage $ = _getERC20WrapperStorage();
    if (address(underlyingToken) == address(this)) {
        revert ERC20InvalidUnderlying(address(this));
    }
    $._underlying = underlyingToken;
}

function depositFor(address account, uint256 value) public virtual returns (bool) {
    ERC20WrapperStorage storage $ = _getERC20WrapperStorage();
    address sender = _msgSender();
    if (sender == address(this)) {
        revert ERC20InvalidSender(address(this));
    }
    if (account == address(this)) {
        revert ERC20InvalidReceiver(account);
    }
    SafeERC20.safeTransferFrom($._underlying, sender, address(this), value);
    _mint(account, value);
    return true;
}

function withdrawTo(address account, uint256 value) public virtual returns (bool) {
    ERC20WrapperStorage storage $ = _getERC20WrapperStorage();
    if (account == address(this)) {
        revert ERC20InvalidReceiver(account);
    }
    _burn(_msgSender(), value);
    SafeERC20.safeTransfer($._underlying, account, value);
    return true;
}

function batchClaim(
    DistributionInfo[] calldata infos,
    uint256[] calldata partyTokenIds
) external returns (uint128[] memory amountsClaimed) {
    amountsClaimed = new uint128[](infos.length);
    for (uint256 i = 0; i < infos.length; ++i) {
        amountsClaimed[i] = claim(infos[i], partyTokenIds[i]);
    }
}

function _mint(address owner) internal returns (uint256 tokenId) {
    if (owner == address(0)) revert InvalidAddressError();
    tokenId = uint256(uint160(owner));
    if (_owners[tokenId] != owner) {
        _owners[tokenId] = owner;
        emit Transfer(address(0), owner, tokenId);
    } else {
        revert AlreadyMintedError(owner, tokenId);
    }
}

function initialize(
    address _defaultAdmin,
    string memory _contractURI,
    address[] memory _trustedForwarders,
    address[] memory _payees,
    uint256[] memory _shares
) external initializer {
    // Initialize inherited contracts: most base -> most derived
    __ERC2771Context_init(_trustedForwarders);
    __PaymentSplitter_init(_payees, _shares);

    contractURI = _contractURI;
    _setupRole(DEFAULT_ADMIN_ROLE, _defaultAdmin);
}

function burnBatch(address _owner, uint256[] memory _tokenIds, uint256[] memory _amounts) external virtual {
    address caller = msg.sender;

    require(caller == _owner || isApprovedForAll[_owner][caller], "Unapproved caller");
    require(_tokenIds.length == _amounts.length, "Length mismatch");

    for (uint256 i = 0; i < _tokenIds.length; i += 1) {
        require(balanceOf[_owner][_tokenIds[i]] >= _amounts[i], "Not enough tokens owned");
    }

    _burnBatch(_owner, _tokenIds, _amounts);
}

constructor(
    string memory name,
    string memory symbol,
    uint8 decimals_,
    uint256 initial_supply
) ERC20PresetMinterPauser(name, symbol) {
    _decimals = decimals_;
    INITIAL_SUPPLY = initial_supply * (10**uint256(decimals_));
    _mint(msg.sender, INITIAL_SUPPLY);
}

function setManyLandUpdateOperator(
