{
  for (uint i = 0; i < _landIds.length; i++) {
    require(landIdEstate[_landIds[i]] == _estateId, "The LAND is not part of the Estate");
  }
  registry.setManyUpdateOperator(_landIds, _operator);
}

function balanceOfBatch(address[] calldata _owners, uint256[] calldata _ids) external view returns (uint256[] memory) {

    require(_owners.length == _ids.length);

    uint256[] memory balances_ = new uint256[](_owners.length);

    for (uint256 i = 0; i < _owners.length; ++i) {
        balances_[i] = balances[_ids[i]][_owners[i]];
    }

    return balances_;
}

function getNodeSupportedModels(
    uint256 nodeId
) external view returns (uint256[] memory modelIds) {
    uint256 length = nodeSupportedModels[nodeId].length();
    modelIds = new uint256[](length);

    for (uint256 i = 0; i < length; i++) {
        uint256 modelId = nodeSupportedModels[nodeId].at(i);
        modelIds[i] = modelId;
    }
}

function _calculateProtocolFeeAmount(
    uint256 price,
    uint256 strategyId,
    uint256 creatorFeeAmount,
    uint256 minTotalFeeAmount
) private view returns (uint256 protocolFeeAmount) {
    protocolFeeAmount = (price * strategyInfo[strategyId].standardProtocolFeeBp) / ONE_HUNDRED_PERCENT_IN_BP;

    if (protocolFeeAmount + creatorFeeAmount < minTotalFeeAmount) {
        protocolFeeAmount = minTotalFeeAmount - creatorFeeAmount;
    }
}

function setNativeTokenVault(INativeTokenVault _nativeTokenVault) external onlyOwner {
    if (address(nativeTokenVault) != address(0)) {
        revert NativeTokenVaultAlreadySet();
    }
    if (address(_nativeTokenVault) == address(0)) {
        revert ZeroAddress();
    }
    nativeTokenVault = _nativeTokenVault;
    _setAssetHandler(ETH_TOKEN_ASSET_ID, address(_nativeTokenVault));
}

function getPackedUserOperationHash(PackedUserOperation calldata _userOp) public view returns (bytes32) {
    return keccak256(
        abi.encode(
            PACKED_USER_OP_TYPEHASH,
            _userOp.sender,
            _userOp.nonce,
            keccak256(_userOp.initCode),
            keccak256(_userOp.callData),
            _userOp.accountGasLimits,
            _userOp.preVerificationGas,
            _userOp.gasFees,
            keccak256(_userOp.paymasterAndData),
            entryPoint
        )
    );
}

function _getRef(uint256[] calldata blobIndices) private view returns (BlobRef memory) {
    uint256 nBlobs = blobIndices.length;
    require(nBlobs != 0, "No blobs provided");

    bytes32[] memory blobhashes = new bytes32[](nBlobs);
    for (uint256 i; i < nBlobs; ++i) {
        blobhashes[i] = blobhash(blobIndices[i]);
        require(blobhashes[i] != 0, "Blob not found");
    }

    return BlobRef(block.number, blobhashes);
}

